#include <stdio.h>

// Define a function to perform analog-to-digital conversion
int analog_to_digital(float analog_signal) {
 // Define the number of bits for the digital signal
 int num_bits = 8;

 // Calculate the maximum value for the digital signal
 int max_value = (1 << num_bits) - 1;

 // Convert the analog signal to a digital signal
 int digital_signal = (int) (analog_signal * max_value);

 return digital_signal;
}

int main() {
 // Define an analog signal
 float analog_signal = 0.5;

 // Perform analog-to-digital conversion
 int digital_signal = analog_to_digital(analog_signal);

 // Print the digital signal
 printf("Digital signal: %d\n", digital_signal);

 return 0;
}
